{
    "level": "A1–A2",
    "intro": "Konstrukcje <strong>there is</strong> i <strong>there are</strong> pokazują, że <strong>coś istnieje</strong> albo <strong>czegoś nie ma</strong> w danym miejscu.",
    "rules": [
        {
            "label": "Singular",
            "color": "emerald",
            "text": "Dla <strong>jednej</strong> rzeczy używaj <strong>there is</strong>.",
            "example": "There is a lamp on the desk."
        },
        {
            "label": "Plural",
            "color": "blue",
            "text": "Dla <strong>więcej niż jednej</strong> rzeczy używaj <strong>there are</strong>.",
            "example": "There are two cups in the kitchen."
        },
        {
            "label": "Negative / Question",
            "color": "amber",
            "text": "Dodaj <strong>not</strong> albo przesuń <strong>is / are</strong> do przodu, żeby utworzyć pytanie.",
            "example": "There isn't a chair here. / Is there a shop nearby?"
        }
    ]
}

{
    "title": "1. Główne modele",
    "intro": "Najpierw wybierz: jedna rzecz czy więcej niż jedna.",
    "items": [
        {
            "label": "Affirmative",
            "title": "There is + singular",
            "subtitle": "There is a cat in the garden."
        },
        {
            "label": "Affirmative",
            "title": "There are + plural",
            "subtitle": "There are three books on the shelf."
        },
        {
            "label": "Negative",
            "title": "There isn't / There aren't",
            "subtitle": "There isn't a key here. / There aren't any buses now."
        },
        {
            "label": "Question",
            "title": "Is there ...? / Are there ...?",
            "subtitle": "Is there a bank nearby? / Are there any chairs?"
        }
    ]
}

{
    "title": "2. Gdzie to jest przydatne",
    "sections": [
        {
            "label": "W pokoju / domu",
            "color": "emerald",
            "description": "Opisuj, co znajduje się w pokoju, na stole, w torbie albo w domu.",
            "examples": [
                {
                    "en": "There is a sofa in the living room.",
                    "ua": "W salonie jest sofa."
                },
                {
                    "en": "There are clean plates in the cupboard.",
                    "ua": "W szafce są czyste talerze."
                }
            ]
        },
        {
            "label": "Z any w przeczeniach i pytaniach",
            "color": "blue",
            "description": "W przeczeniach i pytaniach często pojawia się <strong>any</strong>.",
            "examples": [
                {
                    "en": "There isn't any milk in the fridge.",
                    "ua": "W lodówce nie ma mleka."
                },
                {
                    "en": "Are there any students in the classroom?",
                    "ua": "Czy w klasie są jacyś uczniowie?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "W krótkich odpowiedziach powtarzaj <strong>is</strong> albo <strong>are</strong>.",
            "examples": [
                {
                    "en": "Is there a pharmacy here? — Yes, there is.",
                    "ua": "Tak, jest."
                },
                {
                    "en": "Are there any tickets? — No, there aren't.",
                    "ua": "Nie, nie ma."
                }
            ]
        }
    ]
}

{
    "title": "3. Liczba pojedyncza vs mnoga",
    "intro": "Zobacz, jak model zmienia się od jednej rzeczy do kilku.",
    "rows": [
        {
            "en": "There is a chair in the room.",
            "ua": "Jedna rzecz",
            "note": "is + singular noun"
        },
        {
            "en": "There are two chairs in the room.",
            "ua": "Więcej niż jedna rzecz",
            "note": "are + plural noun"
        },
        {
            "en": "Is there a chair in the room?",
            "ua": "Pytanie",
            "note": "is before there"
        },
        {
            "en": "Are there two chairs in the room?",
            "ua": "Pytanie",
            "note": "are before there"
        }
    ],
    "warning": "📌 Nie mów <strong>There are a chair</strong> ani <strong>There is two chairs</strong>."
}

{
    "title": "4. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Używanie are z rzeczownikiem w liczbie pojedynczej.",
            "wrong": "❌ There are a lamp on the table.",
            "right": "✅ <span class=\"font-mono\">There is a lamp on the table.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie is z liczbą mnogą.",
            "wrong": "❌ There is two shops nearby.",
            "right": "✅ <span class=\"font-mono\">There are two shops nearby.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mieszanie there is z it is.",
            "wrong": "❌ It is a book on the desk.",
            "right": "✅ <span class=\"font-mono\">There is a book on the desk.</span>"
        }
    ]
}

{
    "title": "5. Krótkie podsumowanie",
    "items": [
        "<strong>There is</strong> = jedna rzecz.",
        "<strong>There are</strong> = więcej niż jedna rzecz albo osoba.",
        "Przeczenie: <strong>there isn't</strong> / <strong>there aren't</strong>.",
        "Pytanie: <strong>Is there...?</strong> / <strong>Are there...?</strong>",
        "Model z <strong>there</strong> jest potrzebny, gdy mówisz o istnieniu czegoś w miejscu."
    ]
}

